// Industry search queries - rotate through automation-friendly businesses
const queries = [
  'real estate agency',
  'law firm',
  'dental practice',
  'medical practice',
  'accounting firm',
  'insurance broker',
  'marketing agency',
  'consulting firm',
  'recruitment agency',
  'financial advisor',
  'salon spa',
  'gym fitness',
  'restaurant',
  'retail store',
  'construction company',
  'logistics company',
  'automotive dealer',
  'hotel guest house',
  'veterinary clinic',
  'property management'
];

// Area rotation - 24 Johannesburg/Gauteng/Pretoria locations
const areas = [
  'Johannesburg CBD, Johannesburg, South Africa',
  'Sandton, Johannesburg, South Africa',
  'Fourways, Johannesburg, South Africa',
  'Randburg, Johannesburg, South Africa',
  'Bryanston, Johannesburg, South Africa',
  'Midrand, Gauteng, South Africa',
  'Rosebank, Johannesburg, South Africa',
  'Roodepoort, Johannesburg, South Africa',
  'Soweto, Johannesburg, South Africa',
  'Bedfordview, Johannesburg, South Africa',
  'Kempton Park, Gauteng, South Africa',
  'Germiston, Gauteng, South Africa',
  'Benoni, Gauteng, South Africa',
  'Boksburg, Gauteng, South Africa',
  'Springs, Gauteng, South Africa',
  'Alberton, Gauteng, South Africa',
  'Centurion, Pretoria, South Africa',
  'Pretoria CBD, Pretoria, South Africa',
  'Hatfield, Pretoria, South Africa',
  'Menlyn, Pretoria, South Africa',
  'Brooklyn, Pretoria, South Africa',
  'Vanderbijlpark, Gauteng, South Africa',
  'Vereeniging, Gauteng, South Africa',
  'Krugersdorp, Gauteng, South Africa'
];

const staticData = $getWorkflowStaticData('global');
let queryIndex = staticData.queryIndex || 0;
let areaIndex = staticData.areaIndex || 0;

// Advance to next industry query each run
queryIndex = (queryIndex + 1) % queries.length;

// When we've cycled through all queries, advance to next area
if (queryIndex === 0) {
  areaIndex = (areaIndex + 1) % areas.length;
}

// Save state for next run
staticData.queryIndex = queryIndex;
staticData.areaIndex = areaIndex;

const currentQuery = queries[queryIndex];
const currentArea = areas[areaIndex];

return {
  json: {
    searchQuery: currentQuery,
    location: currentArea,
    queryIndex: queryIndex,
    areaIndex: areaIndex,
    totalQueries: queries.length,
    totalAreas: areas.length,
    maxResults: 20,
    senderName: 'Ian Immelman',
    senderCompany: 'AnyVision Media',
    senderTitle: 'Director',
    senderEmail: 'ian@anyvisionmedia.com',
    googlePlacesApiKey: $env.GOOGLE_PLACES_API_KEY
  }
};

// Parse Google Places API Text Search response
const input = $input.first().json;
const config = $('Search Config').first().json;
const maxResults = parseInt(config.maxResults) || 50;

const places = input.places || [];

if (places.length === 0) {
  return [{ json: { error: 'No businesses found via Places API', query: config.searchQuery, location: config.location } }];
}

// Map Places API response to our business format
const businesses = places.slice(0, maxResults).map(place => ({
  businessName: place.displayName?.text || '',
  website: place.websiteUri || '',
  address: place.formattedAddress || '',
  phone: place.internationalPhoneNumber || place.nationalPhoneNumber || '',
  rating: place.rating || 0,
  reviewCount: place.userRatingCount || 0,
  googleMapsUrl: place.googleMapsUri || '',
  businessStatus: place.businessStatus || '',
  industry: config.searchQuery,
  location: config.location
}));

return businesses.map(b => ({ json: b }));

const inputData = $input.first().json;
const html = inputData.data || inputData.body || '';

// Get original business data from the loop
let original;
try {
  original = $('Loop Over Businesses').item.json;
} catch(e) {
  original = inputData;
}

// Email extraction (exclude image/asset extensions)
const emailRegex = /[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.(?!jpeg|jpg|png|gif|webp|svg|css|js)[a-zA-Z]{2,}/g;
const rawEmails = html.match(emailRegex) || [];
const emails = [...new Set(rawEmails.map(e => e.toLowerCase()))];

// Phone extraction
const phoneRegex = /(?:\+\d{1,3}[\s.-]?)?\(?\d{2,4}\)?[\s.-]?\d{3,4}[\s.-]?\d{3,4}/g;
const rawPhones = html.match(phoneRegex) || [];
const phones = [...new Set(rawPhones)].filter(p => p.replace(/\D/g, '').length >= 7);

// Social media extraction
const linkedinRegex = /https?:\/\/(?:www\.)?linkedin\.com\/(?:company|in)\/[^\s"'<>)]+/gi;
const facebookRegex = /https?:\/\/(?:www\.)?facebook\.com\/[^\s"'<>)]+/gi;
const instagramRegex = /https?:\/\/(?:www\.)?instagram\.com\/[^\s"'<>)]+/gi;

const linkedin = (html.match(linkedinRegex) || [])[0] || '';
const facebook = (html.match(facebookRegex) || [])[0] || '';
const instagram = (html.match(instagramRegex) || [])[0] || '';

// Merge with original business data
const result = {
  businessName: original.businessName || '',
  website: original.website || '',
  address: original.address || '',
  phone: phones[0] || original.phone || '',
  rating: original.rating || 0,
  industry: original.industry || '',
  location: original.location || '',
  emails: emails,
  linkedin: linkedin,
  facebook: facebook,
  instagram: instagram
};

return { json: result };

const items = $input.all();
const seen = new Set();
const results = [];

const highFitIndustries = [
  'real estate', 'law', 'legal', 'attorney', 'medical', 'dental', 'clinic',
  'consulting', 'agency', 'marketing', 'insurance', 'accounting', 'finance',
  'recruitment', 'staffing', 'financial', 'property management'
];
const mediumFitIndustries = [
  'restaurant', 'retail', 'salon', 'fitness', 'gym', 'spa', 'hotel',
  'guest house', 'veterinary', 'vet', 'beauty', 'wellness'
];
const lowFitIndustries = [
  'manufacturing', 'logistics', 'construction', 'contractor', 'plumbing',
  'electrician', 'hvac', 'landscaping', 'cleaning', 'automotive'
];

for (const item of items) {
  const email = (item.json.emails || item.json.email || '').toString().toLowerCase().trim();
  if (!email || seen.has(email)) continue;
  seen.add(email);

  const industry = (item.json.industry || '').toLowerCase();
  const businessName = (item.json.businessName || '').toLowerCase();
  const combined = industry + ' ' + businessName;

  // Contact completeness score
  let score = 0;
  if (email) score += 20;
  if (item.json.phone) score += 15;
  if (item.json.businessName) score += 15;
  if (item.json.address) score += 10;
  if (item.json.rating > 0) score += 10;
  if (item.json.linkedin || item.json.facebook || item.json.instagram) score += 10;
  if (item.json.website) score += 10;
  if (item.json.phone && email) score += 10;

  // Automation fit scoring
  let automationFit = 'low';
  const matchAny = (list, text) => list.some(t => text.includes(t));

  if (matchAny(highFitIndustries, combined)) {
    automationFit = 'high';
    score += 20;
  } else if (matchAny(mediumFitIndustries, combined)) {
    automationFit = 'medium';
    score += 10;
  } else {
    score += 5;
  }

  results.push({
    json: {
      ...item.json,
      email: email,
      leadScore: Math.min(score, 100),
      automationFit: automationFit,
      status: 'New',
      source: 'Johannesburg Lead Scraper',
      datescraped: new Date().toISOString().split('T')[0]
    }
  });
}

return results.length > 0 ? results : [{ json: { _empty: true } }];

const input = $input.first().json;
const config = $('Search Config').first().json;

// Sanitize text to prevent XSS in HTML emails
function sanitize(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// Get lead data - try multiple upstream sources
let leadEmail, businessName, industry, location;
try {
  const filterData = $('Filter New Leads').item.json;
  leadEmail = filterData.Email || filterData.email || '';
  businessName = filterData['Business Name'] || filterData.businessName || '';
  industry = filterData.Industry || filterData.industry || '';
  location = filterData.Location || filterData.location || '';
} catch(e1) {
  try {
    const scoreData = $('Score Leads').item.json;
    leadEmail = scoreData.email || '';
    businessName = scoreData.businessName || '';
    industry = scoreData.industry || '';
    location = scoreData.location || '';
  } catch(e2) {
    leadEmail = input.email || input.Email || '';
    businessName = input.businessName || input['Business Name'] || 'your business';
    industry = input.industry || input.Industry || '';
    location = input.location || input.Location || '';
  }
}

// Parse AI response
let emailContent;
try {
  const rawText = input.text || input.response || JSON.stringify(input);
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  emailContent = JSON.parse(jsonMatch[0]);
} catch (e) {
  emailContent = {
    subject: 'Partnership opportunity for ' + (businessName || 'your business'),
    body: 'I noticed ' + (businessName || 'your business') + ' in ' + location + ' and wanted to reach out about a potential collaboration that could benefit your ' + industry + ' practice.',
    cta_text: 'Would a brief 10-minute call this week work to explore this?'
  };
}

