const totalLeads = allLeads.length;

const leadsWithEmail = allLeads.filter(i => i.json.email || i.json['Email']);
const emailCount = leadsWithEmail.length;
const noEmailCount = totalLeads - emailCount;

const avgScore = totalLeads > 0
  ? Math.round(allLeads.reduce((sum, i) => sum + (i.json.leadScore || i.json['Lead Score'] || 0), 0) / totalLeads)
  : 0;

const highQuality = allLeads.filter(i => (i.json.leadScore || i.json['Lead Score'] || 0) >= 70);

