}

let emailList = '';
for (const lead of leadsWithEmail) {
  const d = lead.json;
  const name = d.businessName || d['Business Name'] || 'Unknown';
  const email = d.email || d['Email'];
  emailList += '<li style="padding: 4px 0;"><strong>' + name + '</strong> &mdash; ' + email + '</li>';
}

