return results.length > 0 ? results : [{ json: { _empty: true } }];

const input = $input.first().json;
const leadData = $('Score Leads').item.json;
const config = $('Search Config').first().json;

// Parse AI response - chainLlm returns text in 'text' field
let emailContent;
try {
  const rawText = input.text || input.response || JSON.stringify(input);
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  emailContent = JSON.parse(jsonMatch[0]);
} catch (e) {
  emailContent = {
    subject: 'Partnership opportunity for ' + (leadData.businessName || 'your business'),
    body: 'I noticed ' + (leadData.businessName || 'your business') + ' in ' + leadData.location + ' and wanted to reach out about a potential collaboration that could benefit your ' + leadData.industry + ' practice.',
